sql:
SELECT Name FROM Artist
WHERE ArtistId IN (
    SELECT al.ArtistId FROM Album al WHERE al.AlbumId IN (
        SELECT t.AlbumId FROM Track t WHERE t.GenreId = 1
    )
)

select c.customer_id, c.first_name, c.last_name
from customer c
where c.customer_id not in (select distinct i.customer_id
from invoice I where i.invoice_date >= date_sub(now(), interval 3 month)
)

select t.track_id, t.name, count (pt.playlist_id) playlists
from track t join playlist_track pt using (track_id)
group by t.track_id, t.name order by playlists desc

